def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English paragraph. Handles mission/crewMembers aggregation to
    produce compact sentences.
    """
    if not triples:
        return ""

    # ---------- Helper utilities ----------
    def fmt_date(d: str) -> str:
        try:
            from datetime import datetime
            dt = datetime.strptime(d, "%Y-%m-%d")
            # Use platform‑independent day format
            return dt.strftime("%B %-d, %Y") if hasattr(dt, "strftime") else dt.strftime("%B %d, %Y")
        except Exception:
            return d

    def join_names(names: list[str]) -> str:
        """Join a list of names with commas and 'and'."""
        if not names:
            return ""
        if len(names) == 1:
            return names[0]
        if len(names) == 2:
            return f"{names[0]} and {names[1]}"
        return f"{', '.join(names[:-1])}, and {names[-1]}"

    # ---------- Phrase builder ----------
    def phrase(subj: str, pred: str, obj: str) -> str:
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low = obj.lower()
            if low in ("united states", "usa", "united states of america"):
                return "American"
            # Preserve original capitalization for other nationalities
            return obj
        if p == "occupation":
            return f"served as a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is now retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                parts = []
                if hrs:
                    parts.append(f"{hrs} hour{'s' if hrs != 1 else ''}")
                if rem:
                    parts.append(f"{rem} minute{'s' if rem != 1 else ''}")
                return "spent " + " and ".join(parts) + " in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # generic fallback
        return f"is {obj}"

    # ---------- Aggregate mission/crew data ----------
    from collections import defaultdict

    # Store role information per mission
    mission_info: dict[str, dict[str, list[str]]] = defaultdict(
        lambda: {"commander": [], "backupPilot": [], "crew": []}
    )
    other_triples: list[Triple] = []

    for t in triples:
        p = t.predicate.lower().replace(" ", "")
        if p == "mission":
            # subject is astronaut, object is mission
            mission_info[t.object]["crew"].append(t.subject)
        elif p == "crewmembers":
            mission_info[t.subject]["crew"].append(t.object)
        elif p == "commander":
            # subject is mission, object is person
            mission_info[t.subject]["commander"].append(t.object)
        elif p == "backuppilot":
            mission_info[t.subject]["backupPilot"].append(t.object)
        elif p == "operator":
            # Capture operator for the mission to use possessive form later
            mission_info[t.subject]["operator"] = t.object
        else:
            other_triples.append(t)

    # Group non‑mission triples by their subject (usually astronauts)
    from collections import defaultdict as _dd
    astronaut_desc: dict[str, list[str]] = _dd(list)
    nationality_info: dict[str, str] = {}
    for t in other_triples:
        pred_key = t.predicate.lower().replace(" ", "")
        if pred_key == "nationality":
            nationality_info[t.subject] = t.object.strip().strip('"')
        else:
            astronaut_desc[t.subject].append(phrase(t.subject, t.predicate, t.object))

    sentences: list[str] = []

    # Build a single sentence per mission, embedding astronaut details
    for mission, roles in mission_info.items():
        parts: list[str] = []

        # Operator phrase
        operator = roles.get("operator")
        if operator:
            mission_phrase = f"{operator}‑operated {mission}"
        else:
            mission_phrase = mission

        # Commander phrase
        if roles["commander"]:
            cmd = join_names(roles["commander"])
            parts.append(f"under commander {cmd}")

        # Backup pilot phrase
        if roles["backupPilot"]:
            bp = join_names(roles["backupPilot"])
            parts.append(f"with backup pilot {bp}")

        # Crew members with their personal descriptors
        crew_clauses: list[str] = []
        for astro in roles["crew"]:
            desc = astronaut_desc.get(astro, [])
            # If there is a birth name, move it into parentheses for readability
            birth_name_phrase = ""
            other_phrases = []
            for d in desc:
                if "birth name" in d.lower():
                    birth_name_phrase = d.replace("is also known as", "birth name").strip()
                else:
                    other_phrases.append(d)
            clause = astro
            if birth_name_phrase:
                clause += f" ({birth_name_phrase})"
            if other_phrases:
                clause += " " + " ".join(other_phrases)
            crew_clauses.append(clause.strip())

        if crew_clauses:
            crew_str = join_names(crew_clauses)
            parts.append(f"crew members {crew_str}")

        # Assemble final mission sentence
        if parts:
            sentence = f"{mission_phrase}, " + ", ".join(parts) + "."
        else:
            sentence = f"{mission_phrase}."
        sentences.append(sentence)

    # Process remaining subjects that are not linked to a mission (e.g., standalone astronauts)
    for subj, descs in astronaut_desc.items():
        if subj in mission_info:  # already described as crew
            continue
        nat_adj = ""
        if subj in nationality_info:
            nat = nationality_info[subj]
            low = nat.lower()
            if low in ("united states", "usa", "united states of america"):
                nat_adj = "American "
            else:
                article = "an" if nat[0].lower() in "aeiou" else "a"
                nat_adj = f"{article} {nat} "
        if descs:
            sentence = f"{nat_adj}{subj} " + ", ".join(descs) + "."
        else:
            sentence = f"{nat_adj}{subj}."
        sentences.append(sentence)

    return " ".join(sentences)

# EVOLVE-BLOCK-END

